import React,{useState} from "react";
import axios from "axios";

export default function InteractionForm(){

const [hcp,setHcp]=useState("");
const [type,setType]=useState("");
const [notes,setNotes]=useState("");

const submit=async()=>{
await axios.post("http://localhost:8000/agent",{
action:"log",
payload:{hcp_name:hcp,interaction_type:type,notes:notes}
})
alert("Interaction logged")
}

return(
<div>
<h2>Log HCP Interaction</h2>
<input placeholder="HCP Name" onChange={e=>setHcp(e.target.value)}/><br/>
<input placeholder="Interaction Type" onChange={e=>setType(e.target.value)}/><br/>
<textarea placeholder="Notes" onChange={e=>setNotes(e.target.value)}/><br/>
<button onClick={submit}>Submit</button>
</div>
)
}
